import time
from functools import wraps
from typing import Callable, TypeVar, ParamSpec

import httpx
from loguru import logger
from result import Ok, Err, Result

from constants import (
    MAX_RETRY_ATTEMPTS,
    BACKOFF_BASE,
    MAX_WAIT_SECONDS,
    RETRYABLE_STATUS_CODES,
    LOG_MSG_RETRY_ATTEMPT,
    LOG_MSG_REQUEST_FAILED,
    LOG_MSG_REQUEST_SUCCESS,
    LOG_MSG_NON_RETRYABLE_ERROR,
)

P = ParamSpec("P")
T = TypeVar("T")


def http_retry(
    max_attempts: int = MAX_RETRY_ATTEMPTS,
    backoff_base: float = BACKOFF_BASE,
    max_wait: float = MAX_WAIT_SECONDS,
) -> Callable[[Callable[P, T]], Callable[P, Result[T, str]]]:
    """
    HTTP 请求重试装饰器，使用指数退避策略

    Args:
        max_attempts: 最大重试次数
        backoff_base: 退避基数（指数的底数）
        max_wait: 最大等待时间（秒）

    Returns:
        装饰后的函数，返回 Result[T, str] 类型

    Examples:
        >>> @http_retry()
        ... def fetch_data(url: str) -> httpx.Response:
        ...     response = httpx.get(url)
        ...     response.raise_for_status()
        ...     return response

        >>> @http_retry(max_attempts=5, backoff_base=3)
        ... async def fetch_async(url: str) -> httpx.Response:
        ...     async with httpx.AsyncClient() as client:
        ...         response = await client.get(url)
        ...         response.raise_for_status()
        ...         return response
    """

    def decorator(func: Callable[P, T]) -> Callable[P, Result[T, str]]:
        @wraps(func)
        def sync_wrapper(*args: P.args, **kwargs: P.kwargs) -> Result[T, str]:
            last_error: Exception | None = None

            for attempt in range(1, max_attempts + 1):
                try:
                    result = func(*args, **kwargs)

                    if attempt > 1:
                        logger.info(LOG_MSG_REQUEST_SUCCESS.format(attempt=attempt))

                    return Ok(result)

                except httpx.HTTPStatusError as e:
                    last_error = e

                    # 检查是否为可重试的状态码
                    if e.response.status_code not in RETRYABLE_STATUS_CODES:
                        error_msg = (
                            f"HTTP {e.response.status_code}: {e.response.text}"
                        )
                        logger.error(
                            LOG_MSG_NON_RETRYABLE_ERROR.format(error=error_msg)
                        )
                        return Err(error_msg)

                    if attempt < max_attempts:
                        wait_time = min(
                            backoff_base ** (attempt - 1),
                            max_wait,
                        )
                        logger.warning(
                            LOG_MSG_RETRY_ATTEMPT.format(
                                attempt=attempt,
                                max_attempts=max_attempts,
                                wait_time=wait_time,
                            )
                        )
                        time.sleep(wait_time)

                except (
                    httpx.RequestError,
                    httpx.TimeoutException,
                    httpx.NetworkError,
                ) as e:
                    last_error = e

                    if attempt < max_attempts:
                        wait_time = min(
                            backoff_base ** (attempt - 1),
                            max_wait,
                        )
                        logger.warning(
                            LOG_MSG_RETRY_ATTEMPT.format(
                                attempt=attempt,
                                max_attempts=max_attempts,
                                wait_time=wait_time,
                            )
                        )
                        time.sleep(wait_time)

                except Exception as e:
                    # 非 HTTP 相关错误，不重试
                    error_msg = f"Unexpected error: {type(e).__name__}: {str(e)}"
                    logger.error(LOG_MSG_NON_RETRYABLE_ERROR.format(error=error_msg))
                    return Err(error_msg)

            # 所有重试都失败
            error_msg = f"{type(last_error).__name__}: {str(last_error)}"
            logger.error(
                LOG_MSG_REQUEST_FAILED.format(
                    attempts=max_attempts,
                    error=error_msg,
                )
            )
            return Err(error_msg)

        @wraps(func)
        async def async_wrapper(*args: P.args, **kwargs: P.kwargs) -> Result[T, str]:
            import asyncio

            last_error: Exception | None = None

            for attempt in range(1, max_attempts + 1):
                try:
                    result = await func(*args, **kwargs)

                    if attempt > 1:
                        logger.info(LOG_MSG_REQUEST_SUCCESS.format(attempt=attempt))

                    return Ok(result)

                except httpx.HTTPStatusError as e:
                    last_error = e

                    # 检查是否为可重试的状态码
                    if e.response.status_code not in RETRYABLE_STATUS_CODES:
                        error_msg = (
                            f"HTTP {e.response.status_code}: {e.response.text}"
                        )
                        logger.error(
                            LOG_MSG_NON_RETRYABLE_ERROR.format(error=error_msg)
                        )
                        return Err(error_msg)

                    if attempt < max_attempts:
                        wait_time = min(
                            backoff_base ** (attempt - 1),
                            max_wait,
                        )
                        logger.warning(
                            LOG_MSG_RETRY_ATTEMPT.format(
                                attempt=attempt,
                                max_attempts=max_attempts,
                                wait_time=wait_time,
                            )
                        )
                        await asyncio.sleep(wait_time)

                except (
                    httpx.RequestError,
                    httpx.TimeoutException,
                    httpx.NetworkError,
                ) as e:
                    last_error = e

                    if attempt < max_attempts:
                        wait_time = min(
                            backoff_base ** (attempt - 1),
                            max_wait,
                        )
                        logger.warning(
                            LOG_MSG_RETRY_ATTEMPT.format(
                                attempt=attempt,
                                max_attempts=max_attempts,
                                wait_time=wait_time,
                            )
                        )
                        await asyncio.sleep(wait_time)

                except Exception as e:
                    # 非 HTTP 相关错误，不重试
                    error_msg = f"Unexpected error: {type(e).__name__}: {str(e)}"
                    logger.error(LOG_MSG_NON_RETRYABLE_ERROR.format(error=error_msg))
                    return Err(error_msg)

            # 所有重试都失败
            error_msg = f"{type(last_error).__name__}: {str(last_error)}"
            logger.error(
                LOG_MSG_REQUEST_FAILED.format(
                    attempts=max_attempts,
                    error=error_msg,
                )
            )
            return Err(error_msg)

        # 检查原函数是否为异步函数
        import inspect
        if inspect.iscoroutinefunction(func):
            return async_wrapper
        else:
            return sync_wrapper

    return decorator
